import{_ as h,I as n,c as d,o as g,a4 as t,j as i,J as a,w as o,a as e}from"./chunks/framework.BR-X7tCu.js";const F=JSON.parse('{"title":"Neo-MoFox WebUI 部署指南","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guides/usage/webui_guide.md","filePath":"docs/guides/usage/webui_guide.md","lastUpdated":1781970535000}'),c={name:"docs/guides/usage/webui_guide.md"};function k(b,s,u,f,x,m){const l=n("VPNolebaseInlineLinkPreview"),r=n("NolebaseGitContributors"),p=n("NolebaseGitChangelog");return g(),d("div",null,[s[14]||(s[14]=t('<h1 id="neo-mofox-webui-部署指南" tabindex="-1">Neo-MoFox WebUI 部署指南 <a class="header-anchor" href="#neo-mofox-webui-部署指南" aria-label="Permalink to “Neo-MoFox WebUI 部署指南”">​</a></h1><p>欢迎！这份指南会手把手教你安装并启动 Neo-MoFox WebUI——让你<strong>从命令行地狱中解脱出来</strong>，用浏览器优雅地管理你的机器人。</p><div class="warning custom-block"><p class="custom-block-title">测试阶段</p><p>WebUI 还在测试中，偶尔会闹点小脾气。遇到 bug 别慌，来 GitHub 提 Issue，我们一起修！</p></div><h2 id="第一步-确认你已经装好了主程序" tabindex="-1">第一步：确认你已经装好了主程序 <a class="header-anchor" href="#第一步-确认你已经装好了主程序" aria-label="Permalink to “第一步：确认你已经装好了主程序”">​</a></h2><p>开始之前，确保你已经：</p><ul><li>✅ 安装并能正常运行 Neo-MoFox 主程序</li><li>✅ Neo-MoFox 版本建议为 <code>1.2.0-beta.1</code> 或更高版本</li><li>✅ 能打开 Neo-MoFox 插件市场页面</li></ul><div class="tip custom-block"><p class="custom-block-title">为什么推荐新版？</p><p>新版 Neo-MoFox 已经和插件市场深度集成。安装、订阅、更新插件都更省心，不需要你手动克隆仓库、切换分支、复制文件。</p></div><h2 id="第二步-从插件市场安装-webui" tabindex="-1">第二步：从插件市场安装 WebUI <a class="header-anchor" href="#第二步-从插件市场安装-webui" aria-label="Permalink to “第二步：从插件市场安装 WebUI”">​</a></h2><p>WebUI 推荐从插件市场安装。插件市场页面是：</p>',9)),i("p",null,[a(l,{href:"https://39.96.71.162/plugin/neo-mofox-webui",target:"_blank",rel:"noreferrer"},{default:o(()=>[...s[0]||(s[0]=[e("插件市场页面",-1)])]),_:1})]),s[15]||(s[15]=t(`<h3 id="_2-1-打开插件详情页" tabindex="-1">2.1 打开插件详情页 <a class="header-anchor" href="#_2-1-打开插件详情页" aria-label="Permalink to “2.1 打开插件详情页”">​</a></h3><ol><li>打开浏览器，访问上面的插件市场链接。</li><li>如果是第一次进入插件市场，会先看到 <strong>「首次使用安全提示」</strong> 弹窗。</li><li>仔细阅读提示后，点击右下角的 <strong>「我已知悉」</strong>。</li><li>随后可能会出现 <strong>「更便利·更轮椅」</strong> 的功能提示弹窗，点击右下角的 <strong>「知道了，不再提示」</strong>。</li><li>页面进入 <strong>Neo-MoFox WebUI</strong> 插件详情页后，确认标题显示为 <strong>Neo-MoFox WebUI</strong>，插件 ID 显示为 <code>neo-mofox-webui</code>。</li></ol><div class="danger custom-block"><p class="custom-block-title">安全提醒</p><p>插件市场中的插件由作者自行上传。安装前请确认插件名称、作者、简介和版本信息。WebUI 官方插件详情页会显示 <strong>官方</strong> 标识。</p></div><h3 id="_2-2-找到安装区域" tabindex="-1">2.2 找到安装区域 <a class="header-anchor" href="#_2-2-找到安装区域" aria-label="Permalink to “2.2 找到安装区域”">​</a></h3><p>进入插件详情页后，页面右侧会有一个 <strong>「安装」</strong> 面板。这个面板里通常会显示：</p><ul><li>最新稳定版，例如 <code>v1.0.5</code></li><li>发布时间</li><li>累计下载、订阅人数、评分</li><li><strong>「下载插件」</strong> 按钮</li><li><strong>「订阅更新」</strong> 按钮</li></ul><p>如果窗口比较窄，右侧安装面板可能会被挤到页面下方。向下滚动就能看到。</p><h3 id="_2-3-下载插件包" tabindex="-1">2.3 下载插件包 <a class="header-anchor" href="#_2-3-下载插件包" aria-label="Permalink to “2.3 下载插件包”">​</a></h3><ol><li>在插件详情页右侧 <strong>「安装」</strong> 面板点击 <strong>「下载插件」</strong>。</li><li>浏览器会打开或下载最新版本的插件包。</li><li>如果浏览器只是打开了下载链接，请按浏览器提示保存文件。</li><li>下载完成后，不要解压到随机目录，继续按下一小节放到 Neo-MoFox 的插件目录。</li></ol><h3 id="_2-4-放入-neo-mofox-插件目录" tabindex="-1">2.4 放入 Neo-MoFox 插件目录 <a class="header-anchor" href="#_2-4-放入-neo-mofox-插件目录" aria-label="Permalink to “2.4 放入 Neo-MoFox 插件目录”">​</a></h3><p>将下载到的 WebUI 插件包按 Neo-MoFox 插件安装规则放入主程序的插件目录。通常位置是：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;Neo-MoFox安装目录&gt;/plugins/</span></span></code></pre></div><p>放好后，重启 Neo-MoFox 主程序。重启时请观察日志，确认 <code>neo-mofox-webui</code> 插件已经被加载。</p><div class="tip custom-block"><p class="custom-block-title">版本选择</p><p>如果 <strong>「安装」</strong> 面板显示最新稳定版，例如 <code>v1.0.5</code>，点击 <strong>「下载插件」</strong> 通常会下载这个最新稳定版。需要指定旧版本时，可以切换到页面上的 <strong>「版本」</strong> 标签，在版本列表中点击对应版本右侧的 <strong>「下载」</strong>。</p></div><h3 id="_2-5-建议订阅更新" tabindex="-1">2.5 建议订阅更新 <a class="header-anchor" href="#_2-5-建议订阅更新" aria-label="Permalink to “2.5 建议订阅更新”">​</a></h3><p>在安装面板中点击 <strong>「订阅更新」</strong>。新版 Neo-MoFox 会自动处理已订阅插件的更新流程，不需要额外配置 access token。</p><h2 id="第三步-配置登录密钥" tabindex="-1">第三步：配置登录密钥 <a class="header-anchor" href="#第三步-配置登录密钥" aria-label="Permalink to “第三步：配置登录密钥”">​</a></h2><p>WebUI 安装完成后，还需要给 Neo-MoFox 的 HTTP 路由配置 API Key。编辑 Neo-MoFox 的配置文件：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;Neo-MoFox安装目录&gt;/config/core.toml</span></span></code></pre></div><p>找到 <code>[http_router]</code> 这一节，设置你的 API Key：</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">http_router</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 是否启用 HTTP 路由（必须是 true）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable_http_router = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 监听地址（本机访问用 127.0.0.1，局域网访问用 0.0.0.0）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http_router_host = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;127.0.0.1&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 监听端口（默认 8000，别和其他程序冲突就行）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http_router_port = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8000</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 登录密钥列表（重点在这里！）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api_keys = [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;your-super-secret-key-here&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 改成你自己的密钥</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">安全提醒</p><p><strong>API Key 就像你家钥匙，别随便给别人！</strong></p><p>推荐生成一个随机字符串：</p><ul><li><strong>Windows PowerShell</strong>：<code>[System.Guid]::NewGuid().ToString()</code></li><li><strong>Linux / macOS</strong>：<code>openssl rand -hex 32</code></li></ul><p>把生成的结果复制到 <code>&lt;Neo-MoFox安装目录&gt;/config/core.toml</code> 的 <code>api_keys</code> 列表里。</p></div><p><strong>配置示例</strong>（仅供参考，别直接复制）：</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api_keys = [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;a1b2c3d4-e5f6-7890-abcd-ef1234567890&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><h2 id="第四步-启动主程序" tabindex="-1">第四步：启动主程序 <a class="header-anchor" href="#第四步-启动主程序" aria-label="Permalink to “第四步：启动主程序”">​</a></h2><p>保存配置文件后，启动或重启 Neo-MoFox：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 Neo-MoFox 根目录运行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p>启动成功后，你会在日志里看到类似这样的提示：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━</span></span>
<span class="line"><span>          🌐 WebUI 可访问地址</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━</span></span>
<span class="line"><span>监听地址: 127.0.0.1:8000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>🖥️  本机访问</span></span>
<span class="line"><span>  ▶ http://localhost:8000/webui/frontend</span></span>
<span class="line"><span>  ▶ http://127.0.0.1:8000/webui/frontend</span></span>
<span class="line"><span></span></span>
<span class="line"><span>🌐 局域网访问</span></span>
<span class="line"><span>  ▶ http://192.168.1.100:8000/webui/frontend  ← 推荐</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">看到这个提示就成功了！</p><p>日志里会自动显示所有可访问的地址，包括局域网 IP。手机想访问的话，用带 🌐 标记的那个。</p></div><h2 id="第五步-打开浏览器登录" tabindex="-1">第五步：打开浏览器登录 <a class="header-anchor" href="#第五步-打开浏览器登录" aria-label="Permalink to “第五步：打开浏览器登录”">​</a></h2><ol><li><strong>复制可访问地址</strong>，推荐使用 <code>http://localhost:8000/webui/frontend</code>。</li><li><strong>打开浏览器</strong>，粘贴地址，回车。</li><li><strong>输入密钥</strong>，也就是你刚才在 <code>config/core.toml</code> 里配置的 <code>api_keys</code>。</li><li><strong>点击登录</strong>。</li></ol><p>登录成功后，你会看到 WebUI 仪表盘，可以在浏览器里管理机器人、查看插件、编辑配置、查看日志等。</p><div class="tip custom-block"><p class="custom-block-title">恭喜你！🎉</p><p>到这里你已经完成部署了！现在可以愉快地用浏览器管理机器人了。</p></div><h2 id="常见问题-遇到问题先看这里" tabindex="-1">常见问题（遇到问题先看这里） <a class="header-anchor" href="#常见问题-遇到问题先看这里" aria-label="Permalink to “常见问题（遇到问题先看这里）”">​</a></h2><h3 id="q1-插件市场页面打不开怎么办" tabindex="-1">Q1：插件市场页面打不开怎么办？ <a class="header-anchor" href="#q1-插件市场页面打不开怎么办" aria-label="Permalink to “Q1：插件市场页面打不开怎么办？”">​</a></h3><p><strong>解决方法</strong>：</p><ol><li>确认浏览器能访问 <code>https://39.96.71.162/plugin/neo-mofox-webui</code>。</li><li>如果浏览器提示证书或安全警告，请确认你访问的是本文给出的插件市场地址，再按浏览器提示继续访问。</li><li>如果网络无法连接，稍后重试，或检查本机网络、代理、防火墙设置。</li></ol><h3 id="q2-插件详情页没看到安装面板怎么办" tabindex="-1">Q2：插件详情页没看到安装面板怎么办？ <a class="header-anchor" href="#q2-插件详情页没看到安装面板怎么办" aria-label="Permalink to “Q2：插件详情页没看到安装面板怎么办？”">​</a></h3><p><strong>原因</strong>：窗口宽度较窄时，安装面板可能会移动到页面下方。</p><p><strong>解决方法</strong>：</p><ol><li>在插件详情页向下滚动。</li><li>找到标题为 <strong>「安装」</strong> 的面板。</li><li>在里面点击 <strong>「下载插件」</strong>，或复制 <code>mofox plugin install neo-mofox-webui@版本号</code> 命令。</li></ol><h3 id="q3-运行安装命令提示找不到-mofox" tabindex="-1">Q3：运行安装命令提示找不到 mofox <a class="header-anchor" href="#q3-运行安装命令提示找不到-mofox" aria-label="Permalink to “Q3：运行安装命令提示找不到 mofox”">​</a></h3><p><strong>原因</strong>：当前 Neo-MoFox 环境可能还没有新版插件管理命令。</p><p><strong>解决方法</strong>：</p><ol><li>先更新 Neo-MoFox 主程序到推荐版本。</li><li>重新打开终端，进入 Neo-MoFox 根目录。</li><li>再运行插件市场给出的安装命令。</li><li>如果仍然不可用，可先使用插件市场的 <strong>「下载插件」</strong> 按钮手动下载插件包。</li></ol><h3 id="q4-浏览器显示-无法访问此网站" tabindex="-1">Q4：浏览器显示“无法访问此网站” <a class="header-anchor" href="#q4-浏览器显示-无法访问此网站" aria-label="Permalink to “Q4：浏览器显示“无法访问此网站””">​</a></h3><p><strong>原因</strong>：</p><ul><li>Neo-MoFox 主程序没运行</li><li>WebUI 插件没加载成功</li><li>端口被占用了</li></ul><p><strong>解决方法</strong>：</p><ol><li>确认主程序正在运行，看终端有没有报错。</li><li>检查日志，确认 <code>neo-mofox-webui</code> 插件已加载。</li><li>检查端口占用： <ul><li><strong>Windows</strong>：<code>netstat -ano | findstr :8000</code></li><li><strong>Linux / macOS</strong>：<code>lsof -i :8000</code></li></ul></li><li>如果端口被占用，修改 <code>&lt;Neo-MoFox安装目录&gt;/config/core.toml</code> 里的 <code>http_router_port</code>，改成其他没被占用的端口，例如 <code>8080</code>，然后重启主程序。</li></ol><h3 id="q5-输入密钥后提示-认证失败" tabindex="-1">Q5：输入密钥后提示“认证失败” <a class="header-anchor" href="#q5-输入密钥后提示-认证失败" aria-label="Permalink to “Q5：输入密钥后提示“认证失败””">​</a></h3><p><strong>原因</strong>：</p><ul><li>密钥输入错误，注意大小写和空格</li><li>配置文件里 <code>api_keys</code> 是空的</li><li>修改配置后没有重启主程序</li></ul><p><strong>解决方法</strong>：</p><ol><li>仔细核对密钥是否和配置文件里的完全一致。</li><li>确认 <code>&lt;Neo-MoFox安装目录&gt;/config/core.toml</code> 的 <code>[http_router]</code> 部分里，<code>api_keys</code> 列表不为空。</li><li>修改配置后必须重启主程序。</li></ol><h3 id="q6-局域网访问不了-手机-其他电脑" tabindex="-1">Q6：局域网访问不了（手机 / 其他电脑） <a class="header-anchor" href="#q6-局域网访问不了-手机-其他电脑" aria-label="Permalink to “Q6：局域网访问不了（手机 / 其他电脑）”">​</a></h3><p><strong>原因</strong>：监听地址设置成 <code>127.0.0.1</code> 了。</p><p><strong>解决方法</strong>：</p><p>编辑 <code>config/core.toml</code>，把 <code>http_router_host</code> 改成 <code>0.0.0.0</code>：</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http_router_host = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.0.0.0&quot;</span></span></code></pre></div><p>然后重启主程序。</p><div class="warning custom-block"><p class="custom-block-title">安全提示</p><p><code>0.0.0.0</code> 会让局域网内其他设备也能访问。如果你的路由器做了公网端口转发，也可能暴露到公网。</p><p><strong>如果暴露到公网</strong>，强烈建议：</p><ul><li>使用超级复杂的 API Key</li><li>配置防火墙规则限制访问 IP</li><li>考虑用 Nginx 反向代理加上 HTTPS</li></ul></div><h3 id="q7-想用其他端口怎么办" tabindex="-1">Q7：想用其他端口怎么办？ <a class="header-anchor" href="#q7-想用其他端口怎么办" aria-label="Permalink to “Q7：想用其他端口怎么办？”">​</a></h3><p>编辑 <code>config/core.toml</code>，修改 <code>http_router_port</code>：</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http_router_port = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9999</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 改成你想要的端口</span></span></code></pre></div><p>重启主程序，然后访问：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http://localhost:9999/webui/frontend</span></span></code></pre></div><h2 id="更新-webui" tabindex="-1">更新 WebUI <a class="header-anchor" href="#更新-webui" aria-label="Permalink to “更新 WebUI”">​</a></h2><p>推荐继续通过插件市场更新 WebUI。</p><h3 id="方式一-在插件市场下载新版本" tabindex="-1">方式一：在插件市场下载新版本 <a class="header-anchor" href="#方式一-在插件市场下载新版本" aria-label="Permalink to “方式一：在插件市场下载新版本”">​</a></h3>`,71)),i("ol",null,[i("li",null,[s[2]||(s[2]=e("打开 ",-1)),a(l,{href:"https://39.96.71.162/plugin/neo-mofox-webui",target:"_blank",rel:"noreferrer"},{default:o(()=>[...s[1]||(s[1]=[e("Neo-MoFox WebUI 插件详情页",-1)])]),_:1}),s[3]||(s[3]=e("。",-1))]),s[4]||(s[4]=t("<li>先看右侧 <strong>「安装」</strong> 面板显示的最新稳定版。</li><li>点击 <strong>「下载插件」</strong> 下载最新版本插件包。</li><li>如果需要指定版本，点击页面上的 <strong>「版本」</strong> 标签，在版本列表中点击对应版本右侧的 <strong>「下载」</strong>。</li><li>将下载到的新版本插件包放入 Neo-MoFox 插件目录，按提示覆盖或替换旧版本。</li><li>重启 Neo-MoFox。</li>",5))]),s[16]||(s[16]=i("h3",{id:"方式二-订阅后自动更新",tabindex:"-1"},[e("方式二：订阅后自动更新 "),i("a",{class:"header-anchor",href:"#方式二-订阅后自动更新","aria-label":"Permalink to “方式二：订阅后自动更新”"},"​")],-1)),i("ol",null,[i("li",null,[s[6]||(s[6]=e("打开 ",-1)),a(l,{href:"https://39.96.71.162/plugin/neo-mofox-webui",target:"_blank",rel:"noreferrer"},{default:o(()=>[...s[5]||(s[5]=[e("Neo-MoFox WebUI 插件详情页",-1)])]),_:1}),s[7]||(s[7]=e("。",-1))]),s[8]||(s[8]=i("li",null,[e("在右侧 "),i("strong",null,"「安装」"),e(" 面板点击 "),i("strong",null,"「订阅更新」"),e("。")],-1)),s[9]||(s[9]=i("li",null,"新版 Neo-MoFox 会自动处理已订阅插件的更新流程。",-1))]),s[17]||(s[17]=i("h2",{id:"反馈与贡献",tabindex:"-1"},[e("反馈与贡献 "),i("a",{class:"header-anchor",href:"#反馈与贡献","aria-label":"Permalink to “反馈与贡献”"},"​")],-1)),s[18]||(s[18]=i("p",null,"遇到问题或有建议？欢迎：",-1)),i("ul",null,[i("li",null,[s[11]||(s[11]=e("🐛 ",-1)),a(l,{href:"https://github.com/MoFox-Studio/Neo-MoFox-Webui/issues/new",target:"_blank",rel:"noreferrer"},{default:o(()=>[...s[10]||(s[10]=[e("提交 Bug 报告",-1)])]),_:1})]),s[12]||(s[12]=i("li",null,"💡 提出功能建议",-1)),s[13]||(s[13]=i("li",null,"🛠️ 提交 Pull Request",-1))]),s[19]||(s[19]=i("p",null,"感谢你的使用！祝你玩得开心 🎉",-1)),a(r),a(p)])}const E=h(c,[["render",k]]);export{F as __pageData,E as default};
